from __future__ import annotations
import base64,gzip,lzma
from pathlib import Path
HERE=Path(__file__).resolve().parent
REPO=HERE.parents[3]
parts=sorted((HERE/'source').glob('materializer-v1.8.6.py.xz.b64.part-*'))
if not parts:raise SystemExit('Governed v1.8.6 materializer payload parts are missing.')
# Repair two CRM CSV fixtures omitted from the governed v1.8.5 repository package.
fix=REPO/'modules/ssp/releases/v1.8.5/fixtures';fix.mkdir(parents=True,exist_ok=True)
missing={
'Portfolio_CRM_Consolidated_McFirecoal_v1.8.5.csv':'',
'Portfolio_CRM_Module_Product_Alpha_v1.8.5.csv':'',
}
for name,payload in missing.items():
 path=fix/name
 if not path.exists():path.write_bytes(gzip.decompress(base64.b64decode(payload)))
source=lzma.decompress(base64.b64decode(''.join(path.read_text().strip() for path in parts)))
exec(compile(source,__file__,'exec'))
